function recursiveSound(sec: Sector, soundBlocks: number): void {
  if (sec.validCount === validCount && sec.soundTraversed <= soundBlocks + 1)
    return; // already flooded

  sec.validCount = validCount;
  sec.soundTraversed = soundBlocks + 1;
  sec.soundTarget = soundTarget;

  for (let i = 0; i < sec.lineCount; i++) {
    const check = sec.lines[i];
    if (!(check.flags & ML_TWOSIDED)) continue;
    lineOpening(check);
    if (openrange <= 0) continue; // closed door
    const other = sides[check.sidenum[0]].sector === sec
      ? sides[check.sidenum[1]].sector
      : sides[check.sidenum[0]].sector;
    if (check.flags & ML_SOUNDBLOCK) {
      if (!soundBlocks) recursiveSound(other, 1);
    } else {
      recursiveSound(other, soundBlocks);
    }
  }
}
